// Combine with Play Integrity
suspend fun trustLevel(context: Context, nonce: String): TrustLevel {
  if (isRooted(context)) return TrustLevel.LOW
  val integrity = playIntegrityToken(context, nonce)
  val verdict = api.verifyIntegrity(integrity).deviceVerdict
  return when (verdict) {
    DeviceVerdict.MEETS_STRONG -> TrustLevel.HIGH
    DeviceVerdict.MEETS_BASIC -> TrustLevel.MEDIUM
    else -> TrustLevel.LOW
  }
}

// UX policy
when (trustLevel) {
  TrustLevel.HIGH -> showFullFeatures()
  TrustLevel.MEDIUM -> showFeaturesExceptPayments()
  TrustLevel.LOW -> showWarning("Some features are unavailable on rooted devices")
}

