// AES-GCM encryption pattern (Android)
import javax.crypto.Cipher
import javax.crypto.spec.GCMParameterSpec

fun encrypt(plain: ByteArray, alias: String): EncryptedBlob {
  val key = (java.security.KeyStore.getInstance("AndroidKeyStore").apply { load(null) })
    .getKey(alias, null)
  val cipher = Cipher.getInstance("AES/GCM/NoPadding").apply { init(Cipher.ENCRYPT_MODE, key) }
  val ct = cipher.doFinal(plain)
  return EncryptedBlob(iv = cipher.iv, ciphertext = ct)
}

