// GDPR — wrap analytics start behind consent
fun onConsentGiven(consent: Consent) {
  if (consent.analytics) AnalyticsSDK.start()
  if (consent.crash) CrashlyticsSDK.start()
  if (consent.marketing) MarketingSDK.start()
}

